import{_ as o,o as e,c as r,ag as a}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/oscillator.png",m=JSON.parse('{"title":"Oscillator","description":"","frontmatter":{},"headers":[],"relativePath":"modules/oscillator.md","filePath":"modules/oscillator.md"}'),n={name:"modules/oscillator.md"};function i(d,t,l,c,u,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="oscillator" tabindex="-1">Oscillator <a class="header-anchor" href="#oscillator" aria-label="Permalink to &quot;Oscillator&quot;">​</a></h1><p><strong>Category:</strong> Sound Sources</p><p>Wavetable oscillator with up to 8 drawable waveforms. Draw custom shapes in the editor, or use the built-in sine/saw/square/triangle presets. Morph smoothly between tables using CV or the ADSR breakpoint system for timbral envelopes. Includes 2-operator FM synthesis with ratio tracking.</p><img src="'+s+'" alt="oscillator module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>fm</strong> (audio)</td><td>Audio-rate FM input. Connect another oscillator for through-zero FM.</td></tr><tr><td><strong>note</strong></td><td>MIDI note input (carries pitch + gate + velocity). Connect from MIDIIn or Sequencer.</td></tr><tr><td><strong>freq</strong></td><td>Raw frequency in Hz. Use instead of &#39;note&#39; for direct pitch control from LFO or Scale.</td></tr><tr><td><strong>gain</strong></td><td>Output amplitude 0-1. Modulate with VCA, ADSR, or LFO for tremolo.</td></tr><tr><td><strong>gate</strong></td><td>Starts/stops the sound. 1 = on, 0 = off. From Button, GateIn, or ADSR.</td></tr><tr><td><strong>morph</strong></td><td>Sweeps between wavetables 0-1. Connect an LFO here for classic wavetable animation.</td></tr><tr><td><strong>table_select</strong></td><td>Jump to a specific wavetable index. Integer values.</td></tr><tr><td><strong>pitch_cv</strong></td><td>Pitch modulation in semitones (+/- pitch_range). 0.5 = no shift.</td></tr><tr><td><strong>fm_ratio_cv</strong></td><td>Modulates the FM carrier:modulator ratio.</td></tr><tr><td><strong>fm_amount</strong></td><td>Modulates FM depth. Audio-rate input for complex timbres.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>L</strong> (audio)</td><td>Left audio output.</td></tr><tr><td><strong>R</strong> (audio)</td><td>Right audio output (same as L in mono patches).</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>For a basic subtractive voice: Oscillator -&gt; Filter -&gt; VCA, with an ADSR controlling the VCA gain and optionally the filter cutoff. Use &#39;note&#39; input from MIDIIn for keyboard control. Enable FM in the inspector for metallic/bell tones without needing a second oscillator.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const g=o(n,[["render",i]]);export{m as __pageData,g as default};
